1154: func (s *SecureServingInfo) HostPort() (string, int, error) {
1155: 	if s == nil || s.Listener == nil {
1156: 		return "", 0, fmt.Errorf("no listener found")
1157: 	}
1158: 	addr := s.Listener.Addr().String()
1159: 	host, portStr, err := net.SplitHostPort(addr)
1160: 	if err != nil {
1161: 		return "", 0, fmt.Errorf("failed to get port from listener address %q: %v", addr, err)
1162: 	}
1163: 	port, err := utilsnet.ParsePort(portStr, true)
1164: 	if err != nil {
1165: 		return "", 0, fmt.Errorf("invalid non-numeric port %q", portStr)
1166: 	}
1167: 	return host, port, nil
